export default "/* inlined from ../_variables.css */\n:host {\n  --theme-bg: hsl(0 0% 100%);\n  --theme-bd: hsl(0 0% 100% / .8);\n  --theme-bd-2: hsl(0 0% 100% / .9);\n  --theme-color: hotpink;\n  --theme-blue: hsl(188 90% 45%);\n  --theme-purple: hsl(267 100% 58%);\n\n  --theme-text_color: hsl(0 0% 10%);\n  --theme-icon_color: hsl(0 0% 20%);\n  --theme-icon_hover-bg: hsl(0 0% 95%);\n  --theme-icon_active-bg: hsl(0 0% 90%);\n\n  --layer-top: 2147483647;\n  --layer-1: 2147483646;\n  --layer-2: 2147483645;\n  --layer-3: 2147483644;\n  --layer-4: 2147483643;\n  --layer-5: 2147483642;\n\n  @media (prefers-color-scheme: dark) {\n    --theme-bg: hsl(0 0% 10%);\n    --theme-bd: hsl(0 0% 10% / .8);\n    --theme-bd-2: hsl(0 0% 10% / .9);\n\n    --theme-text_color: hsl(0 0% 80%);\n    --theme-icon_color: hsl(0 0% 60%);\n    --theme-icon_hover-bg: hsl(0 0% 15%);\n    --theme-icon_active-bg: hsl(0 0% 20%);\n  }\n}\n/* inlined from ../_variables.css */\n:host {\n  --theme-bg: hsl(0 0% 100%);\n  --theme-bd: hsl(0 0% 100% / .8);\n  --theme-bd-2: hsl(0 0% 100% / .9);\n  --theme-color: hotpink;\n  --theme-blue: hsl(188 90% 45%);\n  --theme-purple: hsl(267 100% 58%);\n\n  --theme-text_color: hsl(0 0% 10%);\n  --theme-icon_color: hsl(0 0% 20%);\n  --theme-icon_hover-bg: hsl(0 0% 95%);\n  --theme-icon_active-bg: hsl(0 0% 90%);\n\n  --layer-top: 2147483647;\n  --layer-1: 2147483646;\n  --layer-2: 2147483645;\n  --layer-3: 2147483644;\n  --layer-4: 2147483643;\n  --layer-5: 2147483642;\n\n  @media (prefers-color-scheme: dark) {\n    --theme-bg: hsl(0 0% 10%);\n    --theme-bd: hsl(0 0% 10% / .8);\n    --theme-bd-2: hsl(0 0% 10% / .9);\n\n    --theme-text_color: hsl(0 0% 80%);\n    --theme-icon_color: hsl(0 0% 60%);\n    --theme-icon_hover-bg: hsl(0 0% 15%);\n    --theme-icon_active-bg: hsl(0 0% 20%);\n  }\n}\n\n\n:host {\n  --line-color: var(--theme-purple);\n  --line-base: var(--theme-color);\n  --line-width: 1px;\n  --distance-h: 5px;\n  --distance-w: 5px;\n  --line-w: 1px;\n  --line-h: 1px;\n  font-size: 16px;\n}\n\n:host > figure {\n  margin: 0;\n  position: absolute;\n  height: var(--distance-h);\n  width: var(--distance-w);\n  top: var(--top);\n  left: var(--left);\n  right: var(--right);\n  overflow: visible;\n  pointer-events: none;\n  z-index: var(--layer-3);\n  display: flex;\n  align-items: center;\n  flex-direction: var(--direction);\n}\n\n:host > figure figcaption {\n  width: max-content;\n  color: white;\n  text-shadow: 0 0.5px 0 hsla(0, 0%, 0%, 0.4);\n  box-shadow: 0 0.5px 0 hsla(0, 0%, 0%, 0.4);\n  background: var(--line-color);\n  border-radius: 1em;\n  text-align: center;\n  line-height: 1.1;\n  font-size: 0.7em;\n  font-family: system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, sans-serif;\n  padding: 0.25em 0.5em 0.275em;\n  font-variant-numeric: proportional-num oldstyle-nums stacked-fractions slashed-zero;\n}\n\n:host > figure span {\n  background: var(--line-color);\n  height: var(--line-h);\n  width: var(--line-w);\n}\n\n:host > figure div {\n  flex: 2;\n  background: var(--line-color);\n  width: var(--line-w);\n  height: var(--line-h);\n}\n\n:host figure:matches([quadrant=\"bottom\"], [quadrant=\"right\"]) > div:first-of-type,\n:host figure:matches([quadrant=\"top\"], [quadrant=\"left\"]) > div:last-of-type {\n  background: linear-gradient(to var(--quadrant), hotpink 0%, var(--line-color) 100%);\n}\n";
